        return left

    def parse_unary():
        # Handle unary minus
        if pos[0] < len(expr) and expr[pos[0]] == '-':
            pos[0] += 1
            operand = parse_primary()
            return ASTNode('unary', op='-', operand=operand)
        else:
            return parse_primary()

    def parse_primary():
        if pos[0] >= len(expr):
